// ═══════════════════════════ SPLASH ══════════════════════════════════════════
const SplashParticle = ({delay,tx,ty,size,color}) => (
  <div style={{
    position:"absolute",top:"50%",left:"50%",
    width:size,height:size,borderRadius:"50%",background:color,
    pointerEvents:"none",opacity:0,
    animation:`ocParticle 2.4s ease-out ${delay}s forwards`,
    "--tx":tx,"--ty":ty,
  }}/>
);

const Splash = () => {
  const [p, setP] = useState(0);
  useEffect(() => {
    const ts = [
      setTimeout(()=>setP(1), 80),
      setTimeout(()=>setP(2), 320),
      setTimeout(()=>setP(3), 580),
      setTimeout(()=>setP(4), 880),
      setTimeout(()=>setP(5), 1700),
    ];
    return () => ts.forEach(clearTimeout);
  }, []);

  const particles = [
    {delay:.00,tx:"75px", ty:"-95px", size:5, color:T.gold},
    {delay:.06,tx:"-85px",ty:"-70px", size:4, color:T.silver},
    {delay:.12,tx:"100px",ty:"45px",  size:6, color:T.gold},
    {delay:.04,tx:"-55px",ty:"100px", size:4, color:T.goldLight},
    {delay:.18,tx:"35px", ty:"115px", size:5, color:T.silver},
    {delay:.02,tx:"-110px",ty:"25px", size:4, color:T.gold},
    {delay:.14,tx:"120px",ty:"-35px", size:5, color:T.goldLight},
    {delay:.08,tx:"-90px",ty:"-100px",size:3, color:T.silver},
    {delay:.16,tx:"55px", ty:"-110px",size:4, color:T.gold},
    {delay:.10,tx:"-65px",ty:"65px",  size:3, color:T.goldLight},
  ];

  return (
    <div style={{width:"100%",height:"100vh",background:T.obsidian,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",overflow:"hidden",position:"relative"}}>

      {/* Glow ambiente pulsante */}
      <div style={{
        position:"absolute",top:"50%",left:"50%",
        width:p>=1?700:0,height:p>=1?700:0,
        borderRadius:"50%",
        background:`radial-gradient(circle,${T.gold}${p>=1?"0C":"00"} 0%,${T.silver}${p>=1?"04":"00"} 40%,transparent 70%)`,
        transition:"all 1.6s ease",
        pointerEvents:"none",
        animation:p>=4?"ocAmbient 4s ease-in-out infinite":"none",
      }}/>

      {/* Anel externo — rotação lenta */}
      {p>=3&&<div style={{
        position:"absolute",top:"50%",left:"50%",
        width:420,height:420,borderRadius:"50%",
        border:`1px solid ${T.gold}15`,
        animation:"ocRing2 1s cubic-bezier(.2,.8,.3,1) forwards, ocRotate 18s linear 1s infinite",
      }}/>}

      {/* Anel médio — rotação reversa */}
      {p>=3&&<div style={{
        position:"absolute",top:"50%",left:"50%",
        width:300,height:300,borderRadius:"50%",
        border:`1px solid ${T.gold}22`,
        animation:"ocRing1 .9s cubic-bezier(.34,1.56,.64,1) .1s forwards, ocRotateRev 12s linear 1s infinite",
      }}/>}

      {/* Anel interno sólido */}
      {p>=3&&<div style={{
        position:"absolute",top:"50%",left:"50%",
        width:185,height:185,borderRadius:"50%",
        border:`1.5px solid ${T.gold}35`,
        animation:"ocRing3 .8s cubic-bezier(.34,1.56,.64,1) .2s forwards",
      }}/>}

      {/* Partículas */}
      {p>=2&&particles.map((pt,i)=><SplashParticle key={i} {...pt}/>)}

      {/* LOGO — grande, nítida, com glow duplo e float */}
      <div style={{
        position:"relative",zIndex:2,
        display:"flex",flexDirection:"column",alignItems:"center",
        opacity:p>=4?1:0,
        transform:p>=4?"scale(1) rotate(0deg)":"scale(.12) rotate(-28deg)",
        transition:p>=4?"all 1.1s cubic-bezier(.34,1.56,.64,1)":"none",
        animation:p>=5?"ocFloat 5s ease-in-out .5s infinite, ocGoldGlow 4s ease-in-out .5s infinite":"none",
      }}>
        <img
          src={LOGO_SPLASH}
          alt="Obsidian Capital"
          style={{
            width:240,height:240,
            objectFit:"contain",
            display:"block",
            imageRendering:"crisp-edges",
          }}
        />
      </div>

      {/* Tagline */}
      <div style={{
        position:"relative",zIndex:2,marginTop:28,textAlign:"center",
        opacity:p>=5?1:0,
        animation:p>=5?"ocTagIn 1s ease forwards":"none",
      }}>
        <div style={{color:T.textMuted,fontSize:10,letterSpacing:"0.18em",textTransform:"uppercase",fontFamily:"'Cormorant Garamond',serif",fontWeight:400}}>
          Gestão de Investimentos · Fundos de Negociação · Diversificação de Carteira
        </div>
        <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:14,marginTop:16}}>
          <div style={{height:1,background:`linear-gradient(90deg,transparent,${T.gold}60)`,animation:p>=5?"ocLineGrow .9s ease .3s forwards":"none",width:0}}/>
          <div style={{display:"flex",gap:6}}>
            {[0,1,2].map(i=><div key={i} style={{width:4,height:4,borderRadius:"50%",background:T.gold,animation:p>=5?`ocPulse 1.6s ease ${i*.3}s infinite`:"none",opacity:p>=5?1:0}}/>)}
          </div>
          <div style={{height:1,background:`linear-gradient(90deg,${T.gold}60,transparent)`,animation:p>=5?"ocLineGrow .9s ease .3s forwards":"none",width:0}}/>
        </div>
      </div>
    </div>
  );
};

