const TabDashboard = ({isMobile}) => {
  const R=Math.PI/180;
  const pieLabel=({cx,cy,midAngle,innerRadius,outerRadius,percent})=>{
    if(percent<.08)return null;
    const r=innerRadius+(outerRadius-innerRadius)*.55;
    return <text x={cx+r*Math.cos(-midAngle*R)} y={cy+r*Math.sin(-midAngle*R)} fill="white" textAnchor="middle" dominantBaseline="central" fontSize={10} fontWeight={700}>{`${(percent*100).toFixed(0)}%`}</text>;
  };
  return (
    <div style={{display:"flex",flexDirection:"column",gap:16}}>
      <div style={{display:"grid",gridTemplateColumns:isMobile?"1fr 1fr":"repeat(4,1fr)",gap:12}}>
        <OcKpi label="Patrimônio Total"    value={fmt(358000,0)} sub="+3,78% mês"    trend={1}  icon={Wallet}    color={T.gold}      compact={isMobile}/>
        <OcKpi label="Resultado"           value={fmt(12660)}    sub="+3,66% período" trend={1} icon={TrendingUp} color={T.green}    compact={isMobile}/>
        <OcKpi label="Corretoras"          value="3 ativas"      sub="Conectadas"               icon={Building2} color={T.silver}   compact={isMobile}/>
        <OcKpi label="Lucratividade Anual" value="+27,8%"        sub="vs CDI +14,2%" trend={1}  icon={Activity}  color={T.goldLight} compact={isMobile}/>
      </div>
      <div style={{display:"grid",gridTemplateColumns:isMobile?"1fr":"1fr 300px",gap:16}}>
        <OcBox>
          <OcSec sub="Patrimônio líquido consolidado">Evolução Patrimonial</OcSec>
          <ResponsiveContainer width="100%" height={isMobile?155:200}>
            <AreaChart data={histData}>
              <defs><linearGradient id="gGold" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor={T.gold} stopOpacity={.28}/><stop offset="95%" stopColor={T.gold} stopOpacity={0}/></linearGradient></defs>
              <CartesianGrid strokeDasharray="3 3" stroke={T.border}/>
              <XAxis dataKey="m" stroke={T.textMuted} tick={{fontSize:10,fill:T.textMuted}}/>
              <YAxis stroke={T.textMuted} tick={{fontSize:10,fill:T.textMuted}} tickFormatter={fmtK} width={40}/>
              <Tooltip content={<OcTip/>}/>
              <Area type="monotone" dataKey="v" stroke={T.gold} strokeWidth={2} fill="url(#gGold)"/>
            </AreaChart>
          </ResponsiveContainer>
        </OcBox>
        <OcBox>
          <OcSec sub="Por classe de ativo">Alocação Atual</OcSec>
          <ResponsiveContainer width="100%" height={130}>
            <PieChart><Pie data={allocData} cx="50%" cy="50%" innerRadius={38} outerRadius={60} dataKey="value" labelLine={false} label={pieLabel}>{allocData.map((e,i)=><Cell key={i} fill={e.color}/>)}</Pie></PieChart>
          </ResponsiveContainer>
          <div style={{display:"flex",flexDirection:"column",gap:5,marginTop:4}}>
            {allocData.map((a,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                <div style={{display:"flex",alignItems:"center",gap:7}}><div style={{width:7,height:7,borderRadius:"50%",background:a.color}}/><span style={{color:T.textSub,fontSize:11}}>{a.name}</span></div>
                <div style={{display:"flex",gap:10}}><span style={{color:T.textMuted,fontSize:11}}>{a.value}%</span><span style={{color:T.text,fontSize:11,fontFamily:"JetBrains Mono,monospace"}}>{fmt(a.amount,0)}</span></div>
              </div>
            ))}
          </div>
        </OcBox>
      </div>
      <OcBox>
        <OcSec sub="Resultado por instituição">Performance por Corretora</OcSec>
        <div style={{display:"grid",gridTemplateColumns:isMobile?"1fr":"repeat(3,1fr)",gap:12}}>
          {brokersList.map(b=>(
            <div key={b.id} style={{background:T.surface2,border:`1px solid ${T.border}`,borderRadius:10,padding:14}}>
              <div style={{color:T.textMuted,fontSize:11,marginBottom:3}}>{b.name}</div>
              <div style={{color:T.text,fontSize:20,fontWeight:700,fontFamily:"'Cormorant Garamond',serif"}}>{fmt(b.balance,0)}</div>
              <div style={{color:b.pnl>0?T.green:T.red,fontSize:12,marginTop:3,display:"flex",alignItems:"center",gap:3}}>{b.pnl>0?<ArrowUpRight size={12}/>:<ArrowDownRight size={12}/>}{fmt(b.pnl)} ({fmtPct(b.pnlPct)})</div>
            </div>
          ))}
        </div>
      </OcBox>
    </div>
  );
};


